import importlib.resources as _ir
resource_filename = lambda pkg, path: str(_ir.files(pkg).joinpath(path))

import gi
gi.require_version('Gtk', '3.0')  # @UndefinedVariable
from gi.repository import Gtk, Pango  # @UnresolvedImport

import matplotlib
from matplotlib.figure import Figure

from pyxrd.generic.views import BaseView

class RefinerView(BaseView):
    """
        A view for the Refiner object
    """

    builder = resource_filename(__name__, "glade/refine_results.glade")
    top = "window_refine_results"
    modal = True

    def __init__(self, *args, **kwargs):
        BaseView.__init__(self, *args, **kwargs)
        self.get_toplevel().set_transient_for(self.parent.get_toplevel())
        self._setup_log_widget()
        self._setup_matplotlib_figure()

    def _setup_log_widget(self):
        tv = self["txt_refine_log"]
        tv.modify_font(Pango.FontDescription("Monospace 9"))

    def _setup_matplotlib_figure(self):
        self.figure = Figure(dpi=96)
        self.figure.subplots_adjust(
            left=0.12, right=0.88, top=0.92, bottom=0.12,
            hspace=0.4, wspace=0.4
        )
        cdict = {
            'red':   ((0.0, 0.0, 0.0), (0.5, 1.0, 1.0), (1.0, 0.0, 0.0)),
            'green': ((0.0, 0.0, 0.0), (0.5, 1.0, 1.0), (1.0, 0.0, 0.0)),
            'blue':  ((0.0, 0.0, 0.0), (0.5, 1.0, 1.0), (1.0, 0.0, 0.0)),
        }
        self.wbw_cmap = matplotlib.colors.LinearSegmentedColormap('WBW', cdict, 256)

    def update_labels(self, initial, best, last, elapsed=None):
        self["initial_residual"].set_text("%f" % initial)
        self["best_residual"].set_text("%f" % best)
        self["last_residual"].set_text("%f" % last)
        if elapsed is not None:
            mins, secs = divmod(int(elapsed), 60)
            self["elapsed_time"].set_text("%d:%02d" % (mins, secs))

    def set_log_text(self, text):
        self["txt_refine_log"].get_buffer().set_text(text)

    def show_plot_popup(self, png_bytes):
        import io
        from gi.repository import GdkPixbuf

        loader = GdkPixbuf.PixbufLoader.new_with_type('png')
        loader.write(png_bytes)
        loader.close()
        pixbuf = loader.get_pixbuf()

        image = Gtk.Image.new_from_pixbuf(pixbuf)

        scroll = Gtk.ScrolledWindow()
        scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.AUTOMATIC)
        scroll.add(image)

        win = Gtk.Window(title="Parameter space")
        win.set_default_size(1000, 800)
        win.add(scroll)
        win.show_all()

    pass # end of class
